/*
  Use --df-neutral-{step} / --df-brand-{step} / --df-{hue}-{step}.
  Compact mode keeps the detailed var surface so call sites never break;
  values collapse onto the usual stops.
*/

/* Default File UI - design tokens
 *
 * Color ramps live in df-color-scales.css (compact | detailed).
 * Semantic tokens below map onto --df-neutral-* / --df-brand-*.
 */

:root {
  /* Active scale mode is set on <html data-df-color-scale="…">.
     Default (no attribute / detailed) uses the fine ramp. */

  /* --- Semantic surface / content (neutral ramp) --- */
  --background: var(--df-neutral-0);
  --foreground: var(--df-neutral-900);
  --card: var(--df-neutral-0);
  --card-foreground: var(--df-neutral-900);
  --popover: var(--df-neutral-0);
  --popover-foreground: var(--df-neutral-900);
  --primary: var(--df-neutral-850, var(--df-neutral-900));
  --primary-foreground: var(--df-neutral-0);
  --secondary: var(--df-neutral-50);
  --secondary-foreground: var(--df-neutral-850, var(--df-neutral-900));
  --muted: var(--df-neutral-50);
  --muted-foreground: var(--df-neutral-500);
  --accent: var(--df-neutral-50);
  --accent-foreground: var(--df-neutral-850, var(--df-neutral-900));
  --destructive: oklch(0.577 0.245 27.325);
  --border: var(--df-neutral-100);
  --input: var(--df-neutral-100);
  --ring: var(--df-neutral-400);

  --chart-1: var(--df-neutral-200);
  --chart-2: var(--df-neutral-500);
  --chart-3: var(--df-neutral-600);
  --chart-4: var(--df-neutral-700);
  --chart-5: var(--df-neutral-800);

  --radius: 0.625rem;
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);

  --sidebar: var(--df-neutral-20, var(--df-neutral-50));
  --sidebar-foreground: var(--df-neutral-900);
  --sidebar-primary: var(--df-neutral-850, var(--df-neutral-900));
  --sidebar-primary-foreground: var(--df-neutral-0);
  --sidebar-accent: var(--df-neutral-50);
  --sidebar-accent-foreground: var(--df-neutral-850, var(--df-neutral-900));
  --sidebar-border: var(--df-neutral-100);
  --sidebar-ring: var(--df-neutral-400);
}

/* Compact mode: steps like 850 / 20 may be missing - fall back already in var().
   Remap a few semantics to guaranteed compact stops. */
[data-df-color-scale="compact"] {
  --primary: var(--df-neutral-900);
  --primary-foreground: var(--df-neutral-0);
  --secondary-foreground: var(--df-neutral-900);
  --accent-foreground: var(--df-neutral-900);
  --sidebar: var(--df-neutral-50);
  --sidebar-primary: var(--df-neutral-900);
  --sidebar-accent-foreground: var(--df-neutral-900);
}

.dark {
  --background: var(--df-neutral-950);
  --foreground: var(--df-neutral-0);
  --card: var(--df-neutral-900);
  --card-foreground: var(--df-neutral-0);
  --popover: var(--df-neutral-900);
  --popover-foreground: var(--df-neutral-0);
  --primary: var(--df-neutral-100);
  --primary-foreground: var(--df-neutral-900);
  --secondary: var(--df-neutral-800);
  --secondary-foreground: var(--df-neutral-0);
  --muted: var(--df-neutral-800);
  --muted-foreground: var(--df-neutral-400);
  --accent: var(--df-neutral-800);
  --accent-foreground: var(--df-neutral-0);
  --destructive: oklch(0.704 0.191 22.216);
  --border: color-mix(in oklch, var(--df-neutral-0) 10%, transparent);
  --input: color-mix(in oklch, var(--df-neutral-0) 15%, transparent);
  --ring: var(--df-neutral-500);
  --chart-1: var(--df-neutral-200);
  --chart-2: var(--df-neutral-500);
  --chart-3: var(--df-neutral-600);
  --chart-4: var(--df-neutral-700);
  --chart-5: var(--df-neutral-800);
  --sidebar: var(--df-neutral-900);
  --sidebar-foreground: var(--df-neutral-0);
  --sidebar-primary: var(--df-brand-500);
  --sidebar-primary-foreground: var(--df-neutral-0);
  --sidebar-accent: var(--df-neutral-800);
  --sidebar-accent-foreground: var(--df-neutral-0);
  --sidebar-border: color-mix(in oklch, var(--df-neutral-0) 10%, transparent);
  --sidebar-ring: var(--df-neutral-500);
}

/* Default File UI - base reset
 *
 * Element defaults use :where() so specificity stays 0 and does not beat
 * component [data-df] rules or utility classes.
 */

:where(*, *::before, *::after) {
  box-sizing: border-box;
  border-color: var(--border);
  outline-color: color-mix(in oklch, var(--ring) 50%, transparent);
}

html {
  font-family: var(--font-sans), ui-sans-serif, system-ui, sans-serif;
  -webkit-text-size-adjust: 100%;
  tab-size: 4;
  line-height: 1.5;
}

body {
  margin: 0;
  min-height: 100dvh;
  background-color: var(--background);
  color: var(--foreground);
}

:where(img, svg, video) {
  display: block;
  max-width: 100%;
}

/* Canvas must not get max-width - WebGL backing-store width would shrink the stage */
:where(canvas) {
  display: block;
}

:where(button, input, optgroup, select, textarea) {
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
  font-weight: inherit;
  letter-spacing: inherit;
  color: inherit;
  margin: 0;
}

:where(button) {
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
}

:where(a) {
  color: inherit;
  text-decoration: inherit;
}

:where(h1, h2, h3, h4, h5, h6, p) {
  margin: 0;
}

:where(ul, ol) {
  margin: 0;
  padding: 0;
  list-style: none;
}

:where(table) {
  border-collapse: collapse;
}

:where(:focus-visible) {
  outline: none;
}

/* Default File UI - animations */

@keyframes df-spin {
  to {
    transform: rotate(360deg);
  }
}

@keyframes df-enter {
  from {
    opacity: var(--df-enter-opacity, 1);
    transform: translate3d(
        var(--df-enter-translate-x, 0),
        var(--df-enter-translate-y, 0),
        0
      )
      scale(var(--df-enter-scale, 1));
  }
}

@keyframes df-exit {
  to {
    opacity: var(--df-exit-opacity, 1);
    transform: translate3d(
        var(--df-exit-translate-x, 0),
        var(--df-exit-translate-y, 0),
        0
      )
      scale(var(--df-exit-scale, 1));
  }
}

@keyframes home-reveal {
  from {
    opacity: 0;
    transform: translateY(14px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes home-shader-drift {
  0% {
    background-position: 0% 40%, 100% 60%, 50% 50%;
  }
  50% {
    background-position: 80% 20%, 20% 80%, 40% 60%;
  }
  100% {
    background-position: 0% 40%, 100% 60%, 50% 50%;
  }
}

@keyframes home-mesh-float {
  0%,
  100% {
    transform: translate3d(0, 0, 0) scale(1);
  }
  50% {
    transform: translate3d(4%, -3%, 0) scale(1.04);
  }
}

@keyframes home-stage-float {
  0%,
  100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-6px);
  }
}

.home-reveal {
  animation: home-reveal 0.7s cubic-bezier(0.22, 1, 0.36, 1) both;
}

.home-grid-fade {
  background-image:
    linear-gradient(to right, oklch(0.8 0.01 260 / 0.18) 1px, transparent 1px),
    linear-gradient(to bottom, oklch(0.8 0.01 260 / 0.18) 1px, transparent 1px);
  background-size: 48px 48px;
  mask-image: linear-gradient(180deg, black 0%, transparent 88%);
}

.home-section-tools {
  background: linear-gradient(
    180deg,
    transparent 0%,
    oklch(0.975 0.006 250 / 0.65) 18%,
    oklch(0.97 0.008 90 / 0.5) 55%,
    transparent 100%
  );
}

.home-preview-frame {
  box-shadow:
    inset 0 1px 0 oklch(1 0 0 / 0.35),
    0 0 0 1px oklch(0.85 0.01 260 / 0.35);
}

.home-preview-shader {
  background-image:
    radial-gradient(ellipse at 20% 30%, oklch(0.78 0.14 40), transparent 55%),
    radial-gradient(ellipse at 80% 20%, oklch(0.72 0.12 220), transparent 50%),
    radial-gradient(ellipse at 50% 90%, oklch(0.7 0.1 320), transparent 55%),
    linear-gradient(135deg, oklch(0.35 0.04 260), oklch(0.22 0.03 280));
  background-size: 140% 140%, 140% 140%, 140% 140%, 100% 100%;
  animation: home-shader-drift 12s ease-in-out infinite;
}

.home-preview-mesh {
  background: oklch(0.96 0.01 90);
}

.home-preview-mesh::before,
.home-preview-mesh::after {
  content: "";
  position: absolute;
  inset: -20%;
  border-radius: 9999px;
  filter: blur(28px);
  animation: home-mesh-float 9s ease-in-out infinite;
}

.home-preview-mesh::before {
  background: radial-gradient(
    circle,
    oklch(0.82 0.08 30 / 0.7),
    transparent 62%
  );
  left: -10%;
  top: -15%;
}

.home-preview-mesh::after {
  background: radial-gradient(
    circle,
    oklch(0.8 0.07 230 / 0.55),
    transparent 60%
  );
  right: -15%;
  bottom: -20%;
  animation-delay: -3s;
}

.home-hero-stage {
  box-shadow:
    0 0 0 1px oklch(1 0 0 / 0.08),
    0 32px 80px -36px oklch(0.2 0.03 260 / 0.55);
}

.home-stage-frame {
  animation: home-stage-float 8s ease-in-out infinite;
}

.home-stage-frame:nth-child(2) {
  animation-delay: -2.5s;
}

.home-stage-frame:nth-child(3) {
  animation-delay: -4.5s;
}

@media (prefers-reduced-motion: reduce) {
  .home-reveal,
  .home-preview-shader,
  .home-preview-mesh::before,
  .home-preview-mesh::after,
  .home-stage-frame {
    animation: none !important;
  }
}

/* Default File UI - component styles (data-variant / data-size)
 *
 * Selectors use :where() so specificity stays 0 - call-site utility
 * classes (e.g. pl-8, w-full, flex-1) can override these defaults.
 */

/* --- Button --- */
:where([data-df="button"]) {
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  border-radius: var(--radius-4xl);
  border: 1px solid transparent;
  background-clip: padding-box;
  font-size: 0.875rem;
  line-height: 1.25rem;
  font-weight: 500;
  white-space: nowrap;
  transition: color 150ms, background-color 150ms, border-color 150ms,
    box-shadow 150ms, transform 150ms;
  outline: none;
  user-select: none;
  cursor: pointer;
}

:where([data-df="button"]:focus-visible) {
  border-color: var(--ring);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--ring) 50%, transparent);
}

:where([data-df="button"]:active:not([aria-haspopup])) {
  transform: translateY(1px);
}

:where([data-df="button"]:disabled),
:where([data-df="button"][aria-disabled="true"]) {
  pointer-events: none;
  opacity: 0.5;
}

:where([data-df="button"][aria-invalid="true"]) {
  border-color: var(--destructive);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--destructive) 20%, transparent);
}

:where([data-df="button"] svg) {
  pointer-events: none;
  flex-shrink: 0;
  width: 1rem;
  height: 1rem;
}

:where([data-df="button"][data-variant="default"]) {
  background-color: var(--primary);
  color: var(--primary-foreground);
}
:where([data-df="button"][data-variant="default"]:hover) {
  background-color: color-mix(in oklch, var(--primary) 80%, var(--background));
}

:where([data-df="button"][data-variant="outline"]) {
  border-color: var(--border);
  background-color: color-mix(in oklch, var(--input) 30%, var(--background));
}
:where([data-df="button"][data-variant="outline"]:hover) {
  background-color: color-mix(in oklch, var(--input) 50%, var(--background));
  color: var(--foreground);
}
:where([data-df="button"][data-variant="outline"][aria-expanded="true"]) {
  background-color: var(--muted);
  color: var(--foreground);
}

:where([data-df="button"][data-variant="secondary"]) {
  background-color: var(--secondary);
  color: var(--secondary-foreground);
}
:where([data-df="button"][data-variant="secondary"]:hover) {
  background-color: color-mix(in oklch, var(--secondary), var(--foreground) 5%);
}

:where([data-df="button"][data-variant="ghost"]:hover) {
  background-color: var(--muted);
  color: var(--foreground);
}
:where([data-df="button"][data-variant="ghost"][aria-expanded="true"]) {
  background-color: var(--muted);
  color: var(--foreground);
}

:where([data-df="button"][data-variant="destructive"]) {
  background-color: color-mix(in oklch, var(--destructive) 10%, var(--background));
  color: var(--destructive);
}
:where([data-df="button"][data-variant="destructive"]:hover) {
  background-color: color-mix(in oklch, var(--destructive) 20%, var(--background));
}

:where([data-df="button"][data-variant="link"]) {
  color: var(--primary);
  text-underline-offset: 4px;
}
:where([data-df="button"][data-variant="link"]:hover) {
  text-decoration: underline;
}

:where([data-df="button"][data-size="default"]) {
  height: 2.25rem;
  padding-inline: 0.75rem;
}
:where([data-df="button"][data-size="xs"]) {
  height: 1.5rem;
  gap: 0.25rem;
  padding-inline: 0.625rem;
  font-size: 0.75rem;
}
:where([data-df="button"][data-size="xs"] svg) {
  width: 0.75rem;
  height: 0.75rem;
}
:where([data-df="button"][data-size="sm"]) {
  height: 2rem;
  gap: 0.25rem;
  padding-inline: 0.75rem;
}
:where([data-df="button"][data-size="lg"]) {
  height: 2.5rem;
  padding-inline: 1rem;
}
:where([data-df="button"][data-size="icon"]) {
  width: 2.25rem;
  height: 2.25rem;
  padding: 0;
}
:where([data-df="button"][data-size="icon-xs"]) {
  width: 1.5rem;
  height: 1.5rem;
  padding: 0;
}
:where([data-df="button"][data-size="icon-xs"] svg) {
  width: 0.75rem;
  height: 0.75rem;
}
:where([data-df="button"][data-size="icon-sm"]) {
  width: 2rem;
  height: 2rem;
  padding: 0;
}
:where([data-df="button"][data-size="icon-lg"]) {
  width: 2.5rem;
  height: 2.5rem;
  padding: 0;
}

:where([data-df="button"]:has([data-icon="inline-end"])) {
  padding-right: 0.625rem;
}
:where([data-df="button"]:has([data-icon="inline-start"])) {
  padding-left: 0.625rem;
}

/* Class-based button look for Link / dfButtonClass() call sites */
.df-btn {
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  border-radius: var(--radius-4xl);
  border: 1px solid transparent;
  background-clip: padding-box;
  font-size: 0.875rem;
  line-height: 1.25rem;
  font-weight: 500;
  white-space: nowrap;
  transition: color 150ms, background-color 150ms, border-color 150ms,
    box-shadow 150ms, transform 150ms;
  outline: none;
  user-select: none;
  cursor: pointer;
  text-decoration: none;
}
.df-btn:focus-visible {
  border-color: var(--ring);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--ring) 50%, transparent);
}
.df-btn svg {
  pointer-events: none;
  flex-shrink: 0;
  width: 1rem;
  height: 1rem;
}
.df-btn-default {
