}
.df-btn:has([data-icon="inline-start"]) {
  padding-left: 0.625rem;
}
.df-btn-lg:has([data-icon="inline-end"]) {
  padding-right: 0.75rem;
}
.df-btn-lg:has([data-icon="inline-start"]) {
  padding-left: 0.75rem;
}

/* Leading / trailing slots - hold an icon or any node (badge, counter, close) */
.df-btn-slot {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  flex-shrink: 0;
}

/* --- Badge --- */
:where([data-df="badge"]) {
  display: inline-flex;
