/* --- Input --- */
:where([data-df="input"]) {
  height: 2.25rem;
  width: 100%;
  min-width: 0;
  border-radius: var(--radius-4xl);
  border: 1px solid var(--input);
  background-color: color-mix(in oklch, var(--input) 30%, var(--background));
  /* Longhands so pl-* / pr-* / px-* utilities override cleanly */
  padding-block: 0.25rem;
  padding-left: 0.75rem;
  padding-right: 0.75rem;
  font-size: 1rem;
  line-height: 1.5;
  transition: color 150ms, background-color 150ms, border-color 150ms,
    box-shadow 150ms;
  outline: none;
}

@media (min-width: 768px) {
