/* --- Search input / search bar --- */
:where([data-df="search-input"]) {
  position: relative;
  width: 100%;
  min-width: 0;
}
:where([data-df="search-input"] [data-df="input"]) {
  min-width: 0;
  text-overflow: ellipsis;
  font-family: inherit;
  font-weight: 400;
  color: var(--foreground);
}
:where([data-df="search-input"] [data-df="input"]::placeholder) {
  color: var(--muted-foreground);
