  font-family: inherit;
  font-weight: 400;
  font-size: inherit;
  line-height: inherit;
  opacity: 1;
}

/* Search icon - one chrome, flipped by data-side */
:where([data-df="search-input-icon"]) {
  pointer-events: none;
  position: absolute;
  top: 50%;
  z-index: 1;
  display: flex;
  width: 0.875rem;
