  height: 0.875rem;
}

/* Default (md) padding - icon side mirrors start ↔ end */
[data-df="search-input"][data-has-icon][data-icon-position="start"] [data-df="input"].df-input {
  padding-left: 2rem;
}
[data-df="search-input"][data-has-icon][data-icon-position="end"] [data-df="input"].df-input {
  padding-right: 2rem;
}
[data-df="search-input"][data-has-trailing][data-icon-position="start"] [data-df="input"].df-input {
