}
[data-df="search-input"][data-has-trailing][data-icon-position="end"] [data-df="input"].df-input {
  padding-right: 3.75rem;
}
[data-df="search-input"][data-state="filled"][data-clearable][data-has-trailing][data-icon-position="start"] [data-df="input"].df-input {
