/* --- Scroll Area ---
 * Overlay scrollbar (matches pre-migration dock panels):
 * reserve pr-2.5 on the viewport, hide native bars, paint a thin thumb.
 */
:where([data-df="scroll-area"]) {
  position: relative;
  overflow: hidden;
